22	// newInstallCommand creates the "ddx install <name>" command.
23	func (f *CommandFactory) newInstallCommand() *cobra.Command {
24		cmd := &cobra.Command{
25			Use:   "install <name>",
26			Short: "Install a package or resource",
27			Long: `Install a package or resource from the DDx registry into the
28	current project under .ddx/plugins/<name>/.
29	
30	Examples:
31	  ddx install helix                        # Install HELIX workflow
32	  ddx install helix --force                # Reinstall even if already up to date
33	  ddx plugin install helix --local ../helix --force
34	  ddx install persona/strict-code-reviewer # Install a single persona`,
35			Args: cobra.ExactArgs(1),
36			RunE: f.runInstall,
37		}
38		cmd.Flags().BoolP("force", "f", false, "Reinstall even if already at the latest version")
39		cmd.Flags().String("local", "", "Install from a local directory instead of the registry")
40		return cmd
41	}
42	
43	func (f *CommandFactory) runInstall(cmd *cobra.Command, args []string) error {
44		out := cmd.OutOrStdout()
45		force, _ := cmd.Flags().GetBool("force")
46		name := args[0]
47	
48		// Ensure install operations resolve relative paths against the project
49		// root (WorkingDir), not the caller's cwd. This prevents creating stale
50		// .ddx/ workspaces in subdirectories.
51		if f.WorkingDir != "" {
52			origDir, _ := os.Getwd()
53			if origDir != f.WorkingDir {
54				if err := os.Chdir(f.WorkingDir); err == nil {
55					defer func() { _ = os.Chdir(origDir) }()
56				}
57			}
58		}
59	
60		// Handle --local: install from a local directory instead of registry.
61		if localPath, _ := cmd.Flags().GetString("local"); localPath != "" {
62			return f.installLocal(name, localPath, force, out)
63		}
64	
65		if registry.IsResourcePath(name) {
66			// Individual resource install (e.g. "persona/strict-code-reviewer")
67			fmt.Fprintf(out, "Installing resource %s...\n", name)
68			entry, err := registry.InstallResource(name)
69			if err != nil {
70				return fmt.Errorf("install resource: %w", err)
71			}
72	
73			state, err := registry.LoadState()
74			if err != nil {
75				return fmt.Errorf("loading state: %w", err)
76			}
77			state.AddOrUpdate(entry)
78			if err := registry.SaveState(state); err != nil {
79				return fmt.Errorf("saving state: %w", err)
80			}
81	
82			fmt.Fprintf(out, "Installed %s\n", name)
83			return nil
84		}
85	
86		// Package install (e.g. "helix")
87		reg := registry.BuiltinRegistry()
88		pkg, err := reg.Find(name)
89		if err != nil {
90			return err
91		}
92	
93		// Fetch actual latest version from GitHub (overrides hardcoded registry version).
94		if release, err := update.FetchLatestReleaseForRepo(pkg.Source); err == nil {
95			pkg.Version = strings.TrimPrefix(release.TagName, "v")
96		}
97	
98		// Check if already installed at the latest version.
99		state, err := registry.LoadState()
100		if err == nil {
101			for _, e := range state.Installed {
102				if e.Name == name {
103					if e.Version == pkg.Version {
104						if !force {
105							fmt.Fprintf(out, "%s %s is already up to date\n", e.Name, e.Version)
106							return nil
107						}
108						fmt.Fprintf(out, "Reinstalling %s %s...\n", e.Name, e.Version)
109					} else {
110						fmt.Fprintf(out, "Updating %s from %s to %s...\n", e.Name, e.Version, pkg.Version)
111					}
112				}
113			}
114		}
115	
116		// Capture old file list before installing so we can remove stale files.
117		var oldFiles []string
118		if state != nil {
119			if old := state.FindInstalled(name); old != nil {
120				oldFiles = append([]string{}, old.Files...)
121			}
122		}
123	
124		fmt.Fprintf(out, "Installing %s %s from %s...\n", pkg.Name, pkg.Version, pkg.Source)
125	
126		entry, err := registry.InstallPackage(pkg, f.WorkingDir)
127		if err != nil {
128			return fmt.Errorf("install package: %w", err)
129		}
130	
131		removed := removeStaleFilesFromInstall(oldFiles, entry.Files)
132		if removed > 0 {
133			fmt.Fprintf(out, "Removed %d stale file(s)\n", removed)
134		}
135	
136		state, stateErr := registry.LoadState()
137		if stateErr != nil {
138			return fmt.Errorf("loading state: %w", stateErr)
139		}
140		state.AddOrUpdate(entry)
141		if err := registry.SaveState(state); err != nil {
142			return fmt.Errorf("saving state: %w", err)
143		}
144	
145		fmt.Fprintf(out, "Installed %s %s (%d file(s))\n", pkg.Name, pkg.Version, len(entry.Files))
146	
147		// Auto-commit skill symlinks and other trackable changes.
148		commitPluginChanges(name, pkg.Version)
149	
150		return nil
151	}
