153	func (f *CommandFactory) newPluginCommand() *cobra.Command {
154		cmd := &cobra.Command{
155			Use:     "plugin",
156			Aliases: []string{"plugins"},
157			Short:   "Manage DDx plugins",
158		}
159		installCmd := f.newInstallCommand()
160		installCmd.Use = "install <name>"
161		installCmd.Short = "Install a plugin"
162		cmd.AddCommand(installCmd)
