502	func installLocalSkillSymlinks(pluginRoot, projectRoot string, mappings []registry.InstallMapping, force bool) ([]string, error) {
503		sourceRoots, err := localSkillSourceRoots(pluginRoot, mappings)
504		if err != nil {
505			return nil, err
506		}
507		if len(sourceRoots) == 0 {
508			return nil, nil
509		}
510	
511		var written []string
512		seenSkills := map[string]bool{}
513		for _, sourceRoot := range sourceRoots {
514			entries, err := os.ReadDir(sourceRoot)
515			if err != nil {
516				return nil, err
517			}
518			for _, entry := range entries {
519				if !entry.IsDir() && entry.Type()&os.ModeSymlink == 0 {
520					continue
521				}
522				name := entry.Name()
523				if seenSkills[name] {
524					continue
525				}
526				src := filepath.Join(sourceRoot, name)
527				if _, err := os.Stat(filepath.Join(src, "SKILL.md")); err != nil {
528					return nil, fmt.Errorf("%s: missing SKILL.md: %w", src, err)
529				}
530				for _, surface := range []string{".agents/skills", ".claude/skills"} {
531					dst := filepath.Join(projectRoot, filepath.FromSlash(surface), name)
532					if err := prepareSymlinkTarget(dst, force); err != nil {
533						return nil, err
534					}
535					if err := os.MkdirAll(filepath.Dir(dst), 0o755); err != nil {
536						return nil, fmt.Errorf("creating skills dir: %w", err)
537					}
538					target, err := filepath.Rel(filepath.Dir(dst), src)
539					if err != nil {
540						target = src
541					}
542					if err := os.Symlink(target, dst); err != nil {
543						return nil, fmt.Errorf("linking skill %s -> %s: %w", dst, target, err)
544					}
545					written = append(written, filepath.Join(filepath.FromSlash(surface), name))
546				}
547				seenSkills[name] = true
548			}
549		}
550		return written, nil
551	}
