724	func filterLocalInstallValidationIssues(root string, issues []registry.ValidationIssue) []registry.ValidationIssue {
725		filtered := issues[:0]
726		roots := localInstallRootAliases(root)
727		ignoreCache := map[string]bool{}
728		for _, issue := range issues {
729			if rel, ok := localInstallIssueRel(roots, issue.Path); ok &&
730				(shouldSkipLocalInstallIssue(rel) || localInstallPathIsGitIgnored(root, rel, ignoreCache)) {
731				continue
732			}
733			filtered = append(filtered, issue)
734		}
735		return filtered
736	}
