762	func localInstallRootAliases(root string) []string {
763		seen := map[string]bool{}
764		var roots []string
765		add := func(path string) {
766			if strings.TrimSpace(path) == "" {
767				return
768			}
769			abs, err := filepath.Abs(path)
770			if err != nil {
771				abs = path
772			}
773			if !seen[abs] {
774				seen[abs] = true
775				roots = append(roots, abs)
776			}
777			if resolved, err := filepath.EvalSymlinks(abs); err == nil && resolved != "" && !seen[resolved] {
778				seen[resolved] = true
779				roots = append(roots, resolved)
780			}
781		}
782		add(root)
783		return roots
784	}
785	
786	func localInstallIssueRel(roots []string, path string) (string, bool) {
787		for _, candidate := range localInstallPathAliases(path) {
788			for _, root := range roots {
789				rel, err := filepath.Rel(root, candidate)
790				if err != nil || rel == "." || strings.HasPrefix(rel, ".."+string(filepath.Separator)) || rel == ".." {
791					continue
792				}
793				return filepath.ToSlash(rel), true
794			}
795		}
796		return "", false
797	}
