1070			InstalledVersion string `json:"installed_version"`
1071			LatestVersion    string `json:"latest_version"`
1072		}
1073	
1074		var outdated []outdatedEntry
1075		for _, entry := range state.Installed {
1076			pkg, err := reg.Find(entry.Name)
