337	// downloadAndExtract downloads a .tar.gz from url into destDir and returns
338	// the path of the single top-level directory extracted from the archive.
339	func downloadAndExtract(url, destDir string) (string, error) {
340		resp, err := http.Get(url) //nolint:noctx
341		if err != nil {
342			return "", fmt.Errorf("fetching %s: %w", url, err)
343		}
344		defer func() { _ = resp.Body.Close() }()
345	
346		if resp.StatusCode != http.StatusOK {
347			return "", fmt.Errorf("fetching %s: HTTP %s", url, resp.Status)
348		}
349	
350		gz, err := gzip.NewReader(resp.Body)
351		if err != nil {
352			return "", fmt.Errorf("reading gzip: %w", err)
353		}
354		defer func() { _ = gz.Close() }()
355	
356		tr := tar.NewReader(gz)
357		var topDir string
358	
359		for {
360			hdr, err := tr.Next()
361			if err == io.EOF {
362				break
363			}
364			if err != nil {
365				return "", fmt.Errorf("reading tar: %w", err)
366			}
367	
368			// Sanitize path to prevent directory traversal.
369			clean := filepath.Clean(hdr.Name)
370			if strings.HasPrefix(clean, "..") {
371				continue
372			}
373	
374			dest := filepath.Join(destDir, clean)
375	
376			// Skip PAX global headers (GitHub tarballs include these).
377			if hdr.Typeflag == tar.TypeXGlobalHeader {
378				continue
379			}
380	
381			// Track the top-level directory name.
382			parts := strings.SplitN(clean, string(filepath.Separator), 2)
383			if topDir == "" && parts[0] != "" && parts[0] != "." {
384				topDir = parts[0]
385			}
386	
387			switch hdr.Typeflag {
388			case tar.TypeDir:
389				if err := os.MkdirAll(dest, 0755); err != nil {
390					return "", err
391				}
392			case tar.TypeReg:
393				if err := os.MkdirAll(filepath.Dir(dest), 0755); err != nil {
394					return "", err
395				}
396				f, err := os.OpenFile(dest, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, hdr.FileInfo().Mode())
397				if err != nil {
398					return "", err
399				}
400				if _, err := io.Copy(f, tr); err != nil {
401					_ = f.Close()
402					return "", err
403				}
404				_ = f.Close()
405			case tar.TypeSymlink:
406				if err := os.MkdirAll(filepath.Dir(dest), 0755); err != nil {
407					return "", err
408				}
409				_ = os.Remove(dest)
410				if err := os.Symlink(hdr.Linkname, dest); err != nil {
411					return "", err
412				}
413			}
414		}
415	
416		if topDir == "" {
417			return destDir, nil
418		}
419		return filepath.Join(destDir, topDir), nil
420	}
