// runInstallGlobal installs a plugin into the per-machine global layer at
// ${XDG_DATA_HOME}/ddx/global/plugins/<name> and links <name> into the
// agent-tier skill surfaces under the user's home directory.
func (f *CommandFactory) runInstallGlobal(ctx context.Context, name, localPath string, force bool, out io.Writer) error {
	sourceDir, version, source, cleanup, err := resolveInstallSource(name, localPath)
	if err != nil {
		return err
	}
	defer cleanup()

	home, err := os.UserHomeDir()
	if err != nil {
		return fmt.Errorf("resolving home directory: %w", err)
	}

	entry, err := installLayered(name, sourceDir, ddxroot.GlobalDir(), home, version, source, force, out, "global")
	if err != nil {
		return err
	}
	return recordInstalledEntry(entry)
}

// installConvention installs a plugin into a project that uses the XDG
// convention root (no in-tree .ddx/). The plugin tree lands under
// <conventionRoot>/plugins/<name> while the agent-tier skill links stay
// project-local under <projectRoot>/.claude/skills and <projectRoot>/.agents/skills.
func (f *CommandFactory) installConvention(name, conventionRoot, projectRoot string, force bool, out io.Writer) error {
	sourceDir, version, source, cleanup, err := resolveInstallSource(name, "")
	if err != nil {
		return err
	}
	defer cleanup()

	entry, err := installLayered(name, sourceDir, conventionRoot, projectRoot, version, source, force, out, "project")
	if err != nil {
		return err
	}
	if err := recordInstalledEntry(entry); err != nil {
		return err
	}
	commitPluginChanges(name, version)
	return nil
}

// resolveInstallSource produces an on-disk source directory for the plugin to
// install. When localPath is set it is used directly; otherwise the package
// release tarball is downloaded from the registry into a temp directory. The
// returned cleanup func removes any temporary state.
func resolveInstallSource(name, localPath string) (sourceDir, version, source string, cleanup func(), err error) {
	cleanup = func() {}
	if localPath != "" {
		abs, aerr := filepath.Abs(localPath)
		if aerr != nil {
			return "", "", "", cleanup, fmt.Errorf("resolving path %s: %w", localPath, aerr)
		}
		if _, serr := os.Stat(abs); serr != nil {
			return "", "", "", cleanup, fmt.Errorf("local path does not exist: %s", abs)
		}
		return abs, "local", abs, cleanup, nil
	}

	reg := registry.BuiltinRegistry()
	pkg, ferr := reg.Find(name)
	if ferr != nil {
		return "", "", "", cleanup, ferr
	}
	if release, rerr := update.FetchLatestReleaseForRepo(pkg.Source); rerr == nil {
		pkg.Version = strings.TrimPrefix(release.TagName, "v")
	}
	dir, srcCleanup, derr := registry.FetchPackageSource(pkg)
	if derr != nil {
		return "", "", "", cleanup, derr
	}
	return dir, pkg.Version, pkg.Source, srcCleanup, nil
}

// installLayered materializes the plugin source tree into
// <pluginsRoot>/plugins/<name> and links <name> into the agent-tier skill
// surfaces under surfaceRoot, pointing at the plugin's skills/<name> directory.
// It is the shared core for the --global and project-convention install modes.
func installLayered(name, sourceDir, pluginsRoot, surfaceRoot, version, source string, force bool, out io.Writer, layer string) (registry.InstalledEntry, error) {
	pluginDir := filepath.Join(pluginsRoot, "plugins", name)

	if err := prepareSymlinkTarget(pluginDir, force); err != nil {
		return registry.InstalledEntry{}, err
	}
	if err := os.MkdirAll(pluginDir, 0o755); err != nil {
		return registry.InstalledEntry{}, fmt.Errorf("creating plugin dir %s: %w", pluginDir, err)
	}
	if err := registry.MaterializeFS(os.DirFS(sourceDir), pluginDir); err != nil {
		return registry.InstalledEntry{}, fmt.Errorf("installing plugin into %s: %w", pluginDir, err)
	}

	entry := registry.InstalledEntry{
		Name:        name,
		Version:     version,
		Type:        registry.PackageTypePlugin,
		Source:      source,
		InstalledAt: time.Now(),
		Files:       []string{pluginDir},
	}

	skillSrc := filepath.Join(pluginDir, "skills", name)
	if info, statErr := os.Stat(skillSrc); statErr == nil && info.IsDir() {
		links, linkErr := installAgentTierLinks(name, skillSrc, surfaceRoot, force)
		entry.Files = append(entry.Files, links...)
		if linkErr != nil {
			return entry, linkErr
		}
	}

	fmt.Fprintf(out, "Installed %s %s into %s layer (%s)\n", name, version, layer, pluginDir)
	return entry, nil
}

// installAgentTierLinks creates <surfaceRoot>/.claude/skills/<name> and
// <surfaceRoot>/.agents/skills/<name> as symlinks to skillSrc, falling back to
// a recursive copy on platforms without symlink support. Returns the created
// destination paths.
func installAgentTierLinks(name, skillSrc, surfaceRoot string, force bool) ([]string, error) {
	var written []string
	for _, surface := range []string{".claude/skills", ".agents/skills"} {
		dst := filepath.Join(surfaceRoot, filepath.FromSlash(surface), name)
		if err := prepareSymlinkTarget(dst, force); err != nil {
			return written, err
		}
		if err := os.MkdirAll(filepath.Dir(dst), 0o755); err != nil {
			return written, fmt.Errorf("creating skill surface dir %s: %w", filepath.Dir(dst), err)
		}
		if err := os.Symlink(skillSrc, dst); err != nil {
			// Fallback for platforms lacking symlink support: copy the tree.
			if copyErr := registry.MaterializeFS(os.DirFS(skillSrc), dst); copyErr != nil {
				return written, fmt.Errorf("linking skill %s -> %s: %w", dst, skillSrc, err)
			}
		}
		written = append(written, dst)
	}
	return written, nil
}

// recordInstalledEntry merges entry into the installed-state file.
func recordInstalledEntry(entry registry.InstalledEntry) error {
	state, err := registry.LoadState()
	if err != nil {
		return fmt.Errorf("loading state: %w", err)
	}
	state.AddOrUpdate(entry)
	if err := registry.SaveState(state); err != nil {
		return fmt.Errorf("saving state: %w", err)
	}
	return nil
}

