// FetchPackageSource downloads the package release tarball into a temporary
// directory and returns the extracted source root together with a cleanup func
// that removes the temp directory. Callers that need a materialized source tree
// (e.g. layered global/convention installs) use this instead of the project-
// scoped InstallPackage* entrypoints.
func FetchPackageSource(pkg *Package) (string, func(), error) {
	cleanup := func() {}
	tmpDir, err := os.MkdirTemp("", "ddx-src-"+pkg.Name+"-*")
	if err != nil {
		return "", cleanup, fmt.Errorf("creating temp dir: %w", err)
	}
	cleanup = func() { _ = os.RemoveAll(tmpDir) }

	tarballURL := githubTarballURL(pkg.Source, pkg.Version)
	extractedDir, err := downloadAndExtract(tarballURL, tmpDir)
	if err != nil {
		cleanup()
		return "", func() {}, fmt.Errorf("downloading %s: %w", tarballURL, err)
	}
	return extractedDir, cleanup, nil
}

