// refreshProjectPluginTree re-materializes the embedded default `ddx` plugin
// tree into the active project mode's plugin location — the in-tree
// <project>/.ddx/plugins/ddx or, when the project uses the XDG convention root,
// <conventionRoot>/plugins/ddx. It is a no-op unless the plugin is already
// installed in that mode, so `ddx update` only refreshes what exists.
func refreshProjectPluginTree(ctx context.Context, workingDir string) {
	pluginDir := filepath.Join(ddxroot.Path(ctx, workingDir), "plugins", "ddx")
	if info, err := os.Stat(pluginDir); err != nil || !info.IsDir() {
		return
	}
	if err := registry.MaterializeFS(defaultplugin.FS(), pluginDir); err != nil {
		_, _ = fmt.Fprintf(os.Stderr, "Warning: project plugin refresh failed: %v\n", err)
	}
}

// performUpdateGlobal refreshes the per-machine global plugin layer at
// ${XDG_DATA_HOME}/ddx/global/plugins, leaving the project tree untouched. The
// embedded default `ddx` plugin is re-materialized in place when present so the
// global skill links stay current; other global plugins are refreshed from the
// registry on a best-effort basis.
func performUpdateGlobal() (*UpdateResult, error) {
	pluginsRoot := filepath.Join(ddxroot.GlobalDir(), "plugins")
	entries, err := os.ReadDir(pluginsRoot)
	if err != nil {
		if os.IsNotExist(err) {
			return &UpdateResult{Success: true, Message: "No global plugins installed."}, nil
		}
		return nil, fmt.Errorf("reading global plugins: %w", err)
	}

	reg := registry.BuiltinRegistry()
	var updated []string
	for _, e := range entries {
		if !e.IsDir() {
			continue
		}
		name := e.Name()
		pluginDir := filepath.Join(pluginsRoot, name)
		if name == "ddx" {
			if err := registry.MaterializeFS(defaultplugin.FS(), pluginDir); err != nil {
				return nil, fmt.Errorf("refreshing global ddx plugin: %w", err)
			}
			updated = append(updated, name)
			continue
		}
		pkg, ferr := reg.Find(name)
		if ferr != nil {
			continue
		}
		src, cleanup, derr := registry.FetchPackageSource(pkg)
		if derr != nil {
			continue // best-effort: tolerate offline / network failures
		}
		if merr := registry.MaterializeFS(os.DirFS(src), pluginDir); merr == nil {
			updated = append(updated, name)
		}
		cleanup()
	}

	if len(updated) == 0 {
		return &UpdateResult{Success: true, Message: "Global plugins are up to date."}, nil
	}
	return &UpdateResult{Success: true, Message: "Updated global: " + strings.Join(updated, ", ")}, nil
}

