	require.NoError(t, os.MkdirAll(skillDir, 0o755))
	require.NoError(t, os.WriteFile(filepath.Join(skillDir, "SKILL.md"),
		[]byte("---\nname: "+name+"\ndescription: "+name+" skill\n---\n\nBody.\n"), 0o644))
	require.NoError(t, os.WriteFile(filepath.Join(root, "package.yaml"),
		[]byte("name: "+name+`
version: 1.0.0
description: `+name+` plugin
type: plugin
source: https://example.com/`+name+`
api_version: 1
install:
  root:
    source: .
    target: .ddx/plugins/`+name+`
  skills:
    - source: skills/
      target: .agents/skills/
`), 0o644))
}

// initGitWithRemote initializes a git repo at dir with an origin remote so the
// project resolves to a deterministic XDG convention identity.
func initGitWithRemote(t *testing.T, dir, remoteURL string) {
	t.Helper()
	cleanEnv := gitpkg.CleanEnv()
	for _, args := range [][]string{
		{"init"},
		{"config", "user.email", "test@example.com"},
		{"config", "user.name", "Test User"},
		{"remote", "add", "origin", remoteURL},
	} {
		c := exec.Command("git", args...)
		c.Dir = dir
		c.Env = cleanEnv
		require.NoError(t, c.Run(), "git %v", args)
	}
}

// assertResolvesUnder asserts that linkPath exists (symlink or copy) and that
// its resolved location lives under wantPrefix.
func assertResolvesUnder(t *testing.T, linkPath, wantPrefix string) {
	t.Helper()
	resolved, err := filepath.EvalSymlinks(linkPath)
	require.NoError(t, err, "skill surface entry %s should exist and resolve", linkPath)
	wantResolved, err := filepath.EvalSymlinks(wantPrefix)
	require.NoError(t, err)
	assert.True(t, strings.HasPrefix(resolved, wantResolved),
		"%s should resolve under %s, got %s", linkPath, wantResolved, resolved)
	_, statErr := os.Stat(filepath.Join(linkPath, "SKILL.md"))
	require.NoError(t, statErr, "%s should expose SKILL.md", linkPath)
}

