	for _, surface := range []string{".claude", ".agents"} {
		link := filepath.Join(homeDir, surface, "skills", "widget")
		assertResolvesUnder(t, link, pluginPrefix)
	}
}

// AC2: ddx install <name> (no --global, in-tree mode) installs to
// <project>/.ddx/plugins/<name>/ and creates project-tier links under
// <project>/.claude/skills/<name> and <project>/.agents/skills/<name>.
func TestInstallProject_InTreeLinks(t *testing.T) {
	homeDir := t.TempDir()
	t.Setenv("HOME", homeDir)
	workDir := t.TempDir()

	// In-tree mode: the project has an in-tree .ddx/ directory.
	require.NoError(t, os.MkdirAll(filepath.Join(workDir, ddxroot.DirName), 0o755))

	localPlugin := t.TempDir()
	writeSkillPluginSource(t, localPlugin, "widget")

	factory := NewCommandFactory(workDir)
	output, err := executeCommand(factory.NewRootCommand(), "install", "widget", "--local", localPlugin)
	require.NoError(t, err, output)

	// Plugin tree lands in-tree.
	pluginPrefix := filepath.Join(workDir, ddxroot.DirName, "plugins", "widget")
	_, statErr := os.Stat(filepath.Join(pluginPrefix, "skills", "widget", "SKILL.md"))
	require.NoError(t, statErr, "plugin tree should install under <project>/.ddx/plugins/widget")

	// Project-tier links for both harness surfaces.
	for _, surface := range []string{".claude", ".agents"} {
		link := filepath.Join(workDir, surface, "skills", "widget")
		_, statErr := os.Stat(filepath.Join(link, "SKILL.md"))
		require.NoError(t, statErr, "project skill link %s should resolve to SKILL.md", link)
	}

	// No plugin tree leaks into the global layer or $HOME.
	_, statErr = os.Stat(filepath.Join(homeDir, ddxroot.DirName, "plugins", "widget"))
	assert.True(t, os.IsNotExist(statErr), "in-tree install must not write under $HOME/.ddx/plugins")
}

// AC3: ddx install <name> (no --global, convention mode) installs to
// ${XDG_DATA_HOME}/ddx/projects/<host>/<owner>/<repo>/plugins/<name>/ and creates
// project-tier links pointing into that XDG plugins path.
func TestInstallProject_ConventionLinks(t *testing.T) {
	xdg := t.TempDir()
	t.Setenv("XDG_DATA_HOME", xdg)
	homeDir := t.TempDir()
	t.Setenv("HOME", homeDir)

	// Convention mode: no in-tree .ddx/, identity derived from the git remote.
	projectDir := t.TempDir()
	initGitWithRemote(t, projectDir, "https://github.com/acme/widget.git")

	ctx := context.Background()
	root := ddxroot.Path(ctx, projectDir)
	expectedRoot := filepath.Join(xdg, "ddx", "projects", "github.com", "acme", "widget")
	require.Equal(t, expectedRoot, root, "convention root should be derived from the git remote")

	srcDir := t.TempDir()
	writeSkillPluginSource(t, srcDir, "widget")

	_, err := installLayered("widget", srcDir, root, projectDir, "1.0.0", srcDir, false, io.Discard, "project")
	require.NoError(t, err)

	// Plugin tree under the XDG convention plugins path.
	pluginPrefix := filepath.Join(root, "plugins", "widget")
	_, statErr := os.Stat(filepath.Join(pluginPrefix, "skills", "widget", "SKILL.md"))
	require.NoError(t, statErr, "plugin should install under the XDG convention plugins path")

	// Project-tier links point into the XDG convention plugins path, not in-tree.
	for _, surface := range []string{".claude", ".agents"} {
		link := filepath.Join(projectDir, surface, "skills", "widget")
		assertResolvesUnder(t, link, pluginPrefix)
	}

	_, statErr = os.Stat(filepath.Join(projectDir, ddxroot.DirName, "plugins", "widget"))
	assert.True(t, os.IsNotExist(statErr), "convention install must not write an in-tree plugin tree")
}

