// AC4: ddx update --global updates only the global plugin tree and leaves the
// project tree untouched.
func TestUpdateGlobal_UpdatesGlobalNotProject(t *testing.T) {
	xdg := t.TempDir()
	t.Setenv("XDG_DATA_HOME", xdg)
	homeDir := t.TempDir()
	t.Setenv("HOME", homeDir)
	workDir := t.TempDir()

	// A project skill sentinel that must remain byte-identical after update.
	projectSkill := filepath.Join(workDir, ".agents", "skills", "ddx", "SKILL.md")
	require.NoError(t, os.MkdirAll(filepath.Dir(projectSkill), 0o755))
	require.NoError(t, os.WriteFile(projectSkill, []byte("PROJECT SENTINEL"), 0o644))

	// A stale global ddx plugin that update --global should refresh.
	globalPluginDir := filepath.Join(xdg, "ddx", "global", "plugins", "ddx")
	require.NoError(t, os.MkdirAll(globalPluginDir, 0o755))

	factory := NewCommandFactory(workDir)
	output, err := executeCommand(factory.NewRootCommand(), "update", "--global")
	require.NoError(t, err, output)

	// Project tree untouched: skill sentinel unchanged, no project plugin tree.
	data, rerr := os.ReadFile(projectSkill)
	require.NoError(t, rerr)
	assert.Equal(t, "PROJECT SENTINEL", string(data), "update --global must not rewrite project skills")
	_, statErr := os.Stat(filepath.Join(workDir, ddxroot.DirName, "plugins", "ddx"))
	assert.True(t, os.IsNotExist(statErr), "update --global must not create a project plugin tree")

	// Global ddx plugin refreshed from the embedded default.
	_, statErr = os.Stat(filepath.Join(globalPluginDir, "skills", "ddx", "SKILL.md"))
	require.NoError(t, statErr, "update --global should refresh the global ddx plugin")
}

// AC5: ddx update (no flag) updates the project install in whichever mode is
// active — refreshing the in-tree plugin tree when .ddx/ exists, and the XDG
// convention plugin tree otherwise.
func TestUpdate_RespectsConventionVsInTreeMode(t *testing.T) {
	t.Run("in-tree", func(t *testing.T) {
		homeDir := t.TempDir()
		t.Setenv("HOME", homeDir)
		t.Setenv("XDG_DATA_HOME", t.TempDir())
		workDir := t.TempDir()

		// In-tree ddx plugin installed (stale) under .ddx/plugins/ddx.
		pluginDir := filepath.Join(workDir, ddxroot.DirName, "plugins", "ddx")
		require.NoError(t, os.MkdirAll(pluginDir, 0o755))

		factory := NewCommandFactory(workDir)
		output, err := executeCommand(factory.NewRootCommand(), "update")
		require.NoError(t, err, output)

		_, statErr := os.Stat(filepath.Join(pluginDir, "skills", "ddx", "SKILL.md"))
		require.NoError(t, statErr, "in-tree update should refresh <project>/.ddx/plugins/ddx")
	})

	t.Run("convention", func(t *testing.T) {
		xdg := t.TempDir()
		t.Setenv("XDG_DATA_HOME", xdg)
		homeDir := t.TempDir()
		t.Setenv("HOME", homeDir)

		projectDir := t.TempDir()
		initGitWithRemote(t, projectDir, "https://github.com/acme/widget.git")

		ctx := context.Background()
		root := ddxroot.Path(ctx, projectDir)
		conventionPluginDir := filepath.Join(root, "plugins", "ddx")
		require.NoError(t, os.MkdirAll(conventionPluginDir, 0o755))

		factory := NewCommandFactory(projectDir)
		output, err := executeCommand(factory.NewRootCommand(), "update")
		require.NoError(t, err, output)

		// Convention plugin tree refreshed.
		_, statErr := os.Stat(filepath.Join(conventionPluginDir, "skills", "ddx", "SKILL.md"))
		require.NoError(t, statErr, "convention update should refresh the XDG convention plugin tree")

		// No in-tree plugin tree was created.
		_, statErr = os.Stat(filepath.Join(projectDir, ddxroot.DirName, "plugins", "ddx"))
		assert.True(t, os.IsNotExist(statErr), "convention update must not create an in-tree plugin tree")
	})
}

